if isinstance(businesses, str):
    with open(businesses, 'r') as f:
        businesses = json.load(f)

# Process review business IDs
target_ids = set()
for r in reviews:
    ref = r['business_ref']
    # Convert businessref_X to businessid_X
    if ref.startswith('businessref_'):
        parts = ref.split('_')
        if len(parts) > 1:
            bid = 'businessid_' + parts[1]
            target_ids.add(bid)

count = 0
for b in businesses:
    bid = b.get('business_id')
    if bid not in target_ids:
        continue

    attrs = b.get('attributes')
    if not isinstance(attrs, dict):
        continue

    # Check Bike Parking
    bike_parking = False
    # Check for 'BikeParking' key case-sensitively or assume it matches schema
    # Schema says "BikeParking"
    if 'BikeParking' in attrs:
        val = attrs['BikeParking']
        if val == 'True':
            bike_parking = True

    # Check Business Parking
    business_parking = False
    if 'BusinessParking' in attrs:
        bp_str = attrs['BusinessParking']
        # It's a string representation of a dict, e.g. "{'garage': False...}"
        if bp_str and bp_str != 'None':
            try:
                bp_dict = ast.literal_eval(bp_str)
                if isinstance(bp_dict, dict):
                    # Check if any value is True
                    if any(bp_dict.values()):
                        business_parking = True
            except Exception as e:
                # If parsing fails, ignore
                pass

    if bike_parking or business_parking:
        count += 1

print("__RESULT__:")
print(count)

